const now = new Date();
const d12m = new Date(now); d12m.setFullYear(now.getFullYear() - 1);
const fmt = d => parseInt(`${d.getFullYear()}${String(d.getMonth()+1).padStart(2,'0')}${String(d.getDate()).padStart(2,'0')}`);
return [{ json: { fechaLimite: fmt(d12m) } }];

